INSERT INTO TB_SYS_MENU (
    SYS_MENU_CD, UPR_MENU_CD, MENU_NM, MENU_LVL, MENU_SORT
  , MENU_URL, MENU_SYS_DIV, MENU_DIV, BRD_CD, USE_YN
  , DEL_YN, BIGO, CRE_USR_CD, CRE_DTM, UPD_USR_CD, UPD_DTM
) VALUES (
    #{sysMenuCd}, #{uprMenuCd}, #{menuNm}, #{menuLvl}, #{menuSort}
  , #{menuUrl}, #{menuSysDiv}, #{menuDiv}, #{brdCd}, #{useYn}
  , 'N', #{bigo}, #{ssnUsrCd}, SYSDATE(), #{ssnUsrCd}, SYSDATE()
)
ON DUPLICATE KEY UPDATE
    UPR_MENU_CD  = #{uprMenuCd}
  , MENU_NM      = #{menuNm}
  , MENU_LVL     = #{menuLvl}
  , MENU_SORT    = #{menuSort}
  , MENU_URL     = #{menuUrl}
  , MENU_SYS_DIV = #{menuSysDiv}
  , MENU_DIV     = #{menuDiv}
  , BRD_CD       = #{brdCd}
  , USE_YN       = #{useYn}
  , BIGO         = #{bigo}
  , UPD_USR_CD   = #{ssnUsrCd}
  , UPD_DTM      = SYSDATE()
